    font-weight: 650;
    color: var(--text-heading);
    line-height: 1.35;
}
.repost-embedded-text{
    margin: 0;
    font-family: var(--font-serif);
    font-size: 0.8rem;
    font-weight: 400;
    color: var(--text-body);
    line-height: 1.55;
}
.repost-unavailable{
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 1.5rem;
