/* ── Mobile responsive ── */
@media (max-width: 480px){

    /* ── Mobile top header ── */
    .mobile-top-header{
        display: flex;
        flex-direction: column;
        position: sticky;
        top: 0;
        z-index: 122;
        width: 100%;
        box-sizing: border-box;
        background: var(--bg-primary);
        border-bottom: 1px solid var(--border-card);
        transition: transform 0.3s ease;
    }
    .mobile-top-header-hidden{
        transform: translateY(-100%);
    }
    .mobile-top-header-row{
        display: flex;
        align-items: center;
        justify-content: space-between;
        padding: 0.65rem 0.75rem;
    }
    .mobile-header-tabs{
        display: flex;
        justify-content: space-evenly;
        align-items: center;
        width: 100%;
        padding-bottom: 0.35rem;
    }
    .mobile-header-tab{
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
        font-family: var(--font-ui, sans-serif);
        font-size: 0.82rem;
        font-weight: 600;
        color: var(--text-secondary);
        cursor: pointer;
        padding: 0.25rem 0.5rem;
        -webkit-tap-highlight-color: transparent;
    }
    .mobile-header-tab-underline{
        width: 100%;
        height: 2px;
        margin-top: 0.2rem;
        border-radius: 2px;
        background-color: #D4A853;
    }
    .mobile-brand-text{
        font-family: 'Playfair Display', serif;
        font-size: 1.4rem;
        font-weight: 700;
        color: var(--text-heading);
        letter-spacing: -0.02rem;
    }
    .mobile-header-profile-btn{
        display: flex;
        align-items: center;
        justify-content: center;
        background: none;
        border: 1.5px solid var(--border-card);
        border-radius: 50%;
        padding: 0;
        cursor: pointer;
        -webkit-tap-highlight-color: transparent;
        transition: border-color 0.2s ease;
    }
    .mobile-header-profile-btn:active{
        border-color: #D4A853;
    }
    .mobile-header-profile-btn img{
        width: 30px;
        height: 30px;
        border-radius: 50%;
        object-fit: cover;
    }

    /* ── Search bar visible on mobile ── */
    .search-shell{
        top: 0;
        position: relative;
    }
    .search-top-bar{
        padding: 0.5rem 0.5rem 0.55rem 0.5rem;
        gap: 0.4rem;
    }
    .search-input{
        font-size: 0.8rem;
        padding: 0.5rem 0.75rem 0.5rem 2.1rem;
        border-radius: 8px;
    }
    .search-icon{
        left: 0.7rem;
        width: 14px;
        height: 14px;
    }
    .search-clear-btn{
        font-size: 0.64rem;
        padding: 0.32rem 0.52rem;
        border-radius: 6px;
    }
    .search-nav-row{
        display: none;
    }
    .search-mode-pill{
        font-size: 0.58rem;
        padding: 0.28rem 0.44rem;
        border-radius: 6px;
    }

    .search-suggestions-dropdown{
        left: 0.5rem;
        right: 0.5rem;
        top: calc(100% - 0.1rem);
        max-height: 260px;
        border-radius: 8px;
    }
    .search-suggestion-item{
        padding: 0.52rem 0.7rem;
        border-left-width: 2px;
    }
    .search-suggestion-title{
        font-size: 0.76rem;
    }
    .search-suggestion-meta{
        font-size: 0.62rem;
    }

    /* ── Inline Write button (mobile only) ── */
    .mobile-write-btn{
        display: flex;
        align-items: center;
        gap: 0.3rem;
        border: 1.5px solid rgba(212, 168, 83, 0.4);
        background: linear-gradient(135deg, rgba(212, 168, 83, 0.15), rgba(212, 168, 83, 0.08));
        color: #D4A853;
        border-radius: 8px;
        font-family: var(--font-ui);
        font-size: 0.68rem;
        font-weight: 700;
        letter-spacing: 0.01rem;
        padding: 0.38rem 0.6rem;
        cursor: pointer;
        white-space: nowrap;
        -webkit-tap-highlight-color: transparent;
        transition: background 0.15s ease, transform 0.15s ease;
    }
    .mobile-write-btn:active{
        transform: scale(0.96);
    }
    .mobile-write-btn svg{
        flex-shrink: 0;
    }


    .postcards-parent-container {
        position: relative;
        top: 0;
        display: flex;
        flex-direction: column;
        align-items: center;
        width: 100%;
        margin-top: 0.5rem;
        margin-bottom: 1rem;
        gap: 12px;
        padding: 0 10px;
        box-sizing: border-box;
    }
    .postcards-parent-loading-container {
        position: relative;
        top: 60px;
        display: flex;
        justify-content: center;
        align-items: center;
        flex-direction: column;
        width: 100%;
        height: 100vh;
    }
    .cards{
        border-radius: 10px;
        overflow: visible;
        max-width: 100%;
        box-sizing: border-box;
    }
    .card-image-banner{
        max-height: 220px;
        border-radius: 10px 10px 0 0;
    }
    .card-content{
        width: 100%;
        padding: 0.75rem 0.75rem 0.4rem 0.75rem;
        box-sizing: border-box;
    }
    .content-container {
        display: flex;
        flex-direction: column;
        justify-content: flex-start;
        align-items: flex-start;
        user-select: none;
        gap: 0.3rem;
    }
    .feed-title{
        font-size: 0.92rem;
        line-height: 1.3;
    }
    .feed-text-content {
        padding: 0;
